WebSocket Request Handler Pattern::typescript::type RequestType = 'generate-page' | 'generate-component' | 'suggest-logic';

interface AIRequest {
  type: RequestType;
  context: AppContext;
  userInput: string;
}

const handlers: Record<RequestType, RequestHandler> = {
  'generate-page': new PageGenerationHandler(),
  'generate-component': new ComponentGenerationHandler(),
  'suggest-logic': new LogicSuggestionHandler(),
};

ws.on('message', async (data) => {
  const request = parseRequest(data);
  const handler = handlers[request.type];

  if (!handler) {
    ws.send(JSON.stringify({ error: 'Unknown request type' }));
    return;
  }

  for await (const chunk of handler.process(request)) {
    ws.send(JSON.stringify({ type: 'chunk', data: chunk }));
  }

  ws.send(JSON.stringify({ type: 'complete' }));
});::The router pattern keeps handlers isolated and testable. Each handler implements the same async generator interface, enabling consistent streaming behavior.

Memoized Tree Node Component::tsx::interface TreeNodeProps {
  nodeId: string;
  depth: number;
  onSelect: (id: string) => void;
  onToggle: (id: string) => void;
}

export const TreeNode = memo(function TreeNode({ 
  nodeId, 
  depth, 
  onSelect, 
  onToggle 
}: TreeNodeProps) {
  const node = useNodeData(nodeId);
  const isSelected = useIsSelected(nodeId);
  const isExpanded = useIsExpanded(nodeId);

  const handleSelect = useCallback(() => {
    onSelect(nodeId);
  }, [nodeId, onSelect]);

  const handleToggle = useCallback(() => {
    onToggle(nodeId);
  }, [nodeId, onToggle]);

  if (!node) return null;

  return (
    <div style={{ paddingLeft: depth * 16 }}>
      <NodeContent 
        node={node}
        isSelected={isSelected}
        onSelect={handleSelect}
        onToggle={handleToggle}
      />
      {isExpanded && node.children.map(childId => (
        <TreeNode
          key={childId}
          nodeId={childId}
          depth={depth + 1}
          onSelect={onSelect}
          onToggle={onToggle}
        />
      ))}
    </div>
  );
});::The key patterns: memo() prevents re-render if props are equal, useCallback keeps callback references stable, and custom hooks isolate state subscriptions to minimize re-render scope.
